const DAYS_AGO = 60;
const usernames = [...new Set($input.all().map(item => String(item.json.username || '').trim()).filter(Boolean))];
if (usernames.length === 0) { return [{ json: { should_continue: false, scheduler_alert_type: 'NO_TRACKED_USERS', message: 'Scheduled tracking ran with no tracked users configured.' } }]; }
const startDate = new Date();
startDate.setUTCDate(startDate.getUTCDate() - DAYS_AGO);
return [{ json: { should_continue: true, query: usernames.map(username => `from:${username}`).join(' OR '), start_time: startDate.toISOString(), usernames, user_count: usernames.length } }];

const state = $('Advance Post Suppression State').first()?.json || {};
const rawBlocked = state.blocked_post_ids || [];
const postSearch = $('Get posts of tracked users').first()?.json || {};
const usersById = new Map(
  (postSearch.includes?.users || []).map(user => [String(user.id), user])
);

let blockedIds = [];
if (Array.isArray(rawBlocked)) {
  blockedIds = rawBlocked;
} else if (typeof rawBlocked === 'string') {
  blockedIds = rawBlocked
    .replace(/^\{/, '')
    .replace(/\}$/, '')
    .split(',')
    .map(value => value.replace(/^"|"$/g, '').trim())
    .filter(Boolean);
}

const blocked = new Set(blockedIds.map(String));
return $input.all()
  .filter(item => !blocked.has(String(item.json.id || '')))
  .map(item => {
    const author = usersById.get(String(item.json.author_id)) || {};
    const username = String(author.username || '').trim();
    const name = String(author.name || '').trim();

    return {
      json: {
        ...item.json,
        author_username: username,
        author_name: name,
        post_author: username ? `@${username}` : (name || String(item.json.author_id || 'unknown')),
      },
    };
  });

const conversationIds = [...new Set(
  $input.all()
    .map(item => String(item.json.conversation_id || '').trim())
    .filter(Boolean)
)];

if (conversationIds.length === 0) {
  return [];
}

return [{
  json: {
    query: conversationIds
      .map(id => `(conversation_id:${id} is:reply)`)
      .join(' OR '),
    conversation_ids: conversationIds,
    conversation_count: conversationIds.length,
  },
}];

const postsByConversation = new Map(
  $('Keep Posts With 10+ Replies').all().map(item => [
    String(item.json.conversation_id),
    {
      postId: item.json.id,
      postText: item.json.text,
      userId: item.json.author_id,
      postAuthor: item.json.post_author || (item.json.author_username ? `@${item.json.author_username}` : String(item.json.author_id || 'unknown')),
      authorUsername: item.json.author_username || '',
      authorName: item.json.author_name || '',
      totalReplyCount: Number(item.json.public_metrics?.reply_count ?? 0),
      replies: [],
    },
  ])
);

for (const group of $('Get Replies').all()) {
  for (const reply of group.json.data || []) {
    const post = postsByConversation.get(String(reply.conversation_id));
    if (!post || !reply.id) continue;

    post.replies.push({
      id: reply.id,
      text: String(reply.text || '').replace(/\s+/g, ' ').trim(),
    });
  }
}

return [{
  json: {
    text: JSON.stringify({ results: [...postsByConversation.values()] }),
  },
}];

function parseResults(item) {
  const candidates = [
    item.json?.output?.[0]?.content?.[0]?.text,
    item.json?.output,
    item.json?.text,
  ];

  for (const candidate of candidates) {
    let value = candidate;
    if (typeof value === 'string') {
      try {
        value = JSON.parse(value);
      } catch {
        continue;
      }
    }

    if (Array.isArray(value?.results)) {
      return value.results;
    }
  }

  throw new Error('OpenAI response did not contain a results array.');
}

function parseInputPosts() {
  const raw = $('Attach replies to posts').first()?.json?.text;
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed.results) ? parsed.results : [];
  } catch {
    return [];
  }
}

const inputPostsById = new Map(
  parseInputPosts().map(post => [String(post.postId || ''), post])
);

return items.map(item => {
  const posts = parseResults(item).map(post => {
    const metadata = inputPostsById.get(String(post.postId || '')) || {};
    const replies = Array.isArray(post.replies) ? post.replies : [];
    const counts = { positive: 0, neutral: 0, negative: 0 };

    for (const reply of replies) {
      const sentiment = String(reply.sentiment || '').toLowerCase();
      if (Object.prototype.hasOwnProperty.call(counts, sentiment)) {
        counts[sentiment] += 1;
      }
    }

    const comments_count = replies.length;
    const total_reply_count = Number(metadata.totalReplyCount ?? comments_count);
    const negative_ratio = comments_count > 0
      ? counts.negative / comments_count
      : 0;

    let overall_tag = 'Neutral';
    if (counts.positive > counts.neutral && counts.positive > counts.negative) {
      overall_tag = 'Positive';
    } else if (counts.negative > counts.neutral && counts.negative > counts.positive) {
      overall_tag = 'Negative';
    }

    return {
      postId: post.postId,
      postText: post.postText,
      userId: post.userId || metadata.userId,
      postAuthor: metadata.postAuthor || post.postAuthor || String(post.userId || metadata.userId || 'unknown'),
      authorUsername: metadata.authorUsername || post.authorUsername || '',
      authorName: metadata.authorName || post.authorName || '',
      replies,
      comments_count,
      total_reply_count,
      positive_count: counts.positive,
      neutral_count: counts.neutral,
      negative_count: counts.negative,
      negative_ratio,
      negative_percentage: Math.round(negative_ratio * 100),
      overall_tag,
    };
  });

  return {
    json: {
      posts: posts.filter(post => post.negative_ratio >= 0.5),
    },
  };
});

const allPosts = $("Split Out Reply Analysis").all();

const allReplies = allPosts.flatMap(post => {
  const replies = post.json.replies || [];
  return replies.map(reply => ({
    ...reply,
    postId: post.json.postId,
    postText: post.json.postText
  }));
});

return allReplies.map(reply => ({ json: reply }));

const posts = $('Split Out Reply Analysis').all().map(item => item.json || {});
const replyCountsByPostId = new Map(
  $('Get Reply Status Counts').all().map(item => {
    const row = item.json || {};
    return [String(row.post_id || ''), {
      hiddenNegative: Number(row.hidden_negative_replies_count || 0),
      nonHiddenNegative: Number(row.non_hidden_negative_replies_count || 0),
    }];
  })
);

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

if (posts.length === 0) { return []; }
const telegramUsers = $input.all().map(item => item.json || {}).filter(user => user.chat_id);
if (telegramUsers.length === 0) { return [{ json: { notify_ready: false, scheduler_alert_type: 'NO_TELEGRAM_RECIPIENTS', post_count: posts.length, post_ids: posts.map(post => String(post.postId || '')).filter(Boolean), message: `Scheduled tracking generated ${posts.length} negative alert post(s), but no Telegram recipients are configured.` } }]; }
return telegramUsers.flatMap(user => posts.map((post, index) => {
  const postId = String(post.postId || '');
  const counts = replyCountsByPostId.get(postId) || {};
  const text = escapeHtml(post.postText || '');
  const author = escapeHtml(post.postAuthor || post.authorUsername || post.userId || 'unknown');
  const totalReplies = Number(post.total_reply_count ?? post.comments_count ?? 0);
  const analyzedReplies = Number(post.comments_count ?? 0);
  const negativeCount = Number(post.negative_count ?? 0);
  const hiddenNegativeReplies = Number(counts.hiddenNegative ?? 0);
  const nonHiddenNegativeReplies = Number(counts.nonHiddenNegative ?? Math.max(negativeCount - hiddenNegativeReplies, 0));
  const negativePercentage = post.negative_percentage ?? 0;
  const overall = escapeHtml(post.overall_tag || 'Negative');
  const tweetUrl = `https://x.com/i/web/status/${postId}`;
  const message = [
    '<b>XMonitor Scheduled Post Alert</b>',
    '',
    `<b>Post ${index + 1}</b>`,
    `Author: ${author}`,
    `Post ID: <code>${postId}</code>`,
    `Link: ${tweetUrl}`,
    '',
    '<b>Key Metrics</b>',
    `Total replies: ${totalReplies}`,
    `Analyzed replies: ${analyzedReplies}`,
    `Negative replies: ${negativeCount}`,
    `Hidden negative replies: ${hiddenNegativeReplies}`,
    `Visible negative replies: ${nonHiddenNegativeReplies}`,
    `Negative sentiment: ${negativePercentage}%`,
    `Overall sentiment: ${overall}`,
    '',
    '<b>Post Text</b>',
    text || '(empty)',
  ].join('\n');
  return { json: { notify_ready: true, chat_id: user.chat_id, post_id: postId, message, snooze_button_text: 'Snooze', snooze_callback_data: `snooze:${postId}`, ignore_button_text: 'Ignore', ignore_callback_data: `ignore:${postId}`, hide_button_text: `Hide replies for Post #${index + 1}`, hide_callback_data: `hide_replies:${postId}` } };
}));

const data = $json || {};
const message = ['<b>XMonitor staging handled error</b>','Workflow: Scheduled Post Tracking Staging',`Path: ${data.scheduler_alert_type || 'scheduler validation'}`,`Reason: ${data.message || 'Scheduler stopped before sending alerts.'}`,data.post_count !== undefined ? `Post count: ${data.post_count}` : '',Array.isArray(data.post_ids) && data.post_ids.length ? `Posts: ${data.post_ids.slice(0, 20).join(', ')}` : ''].filter(Boolean).join('\n');
return [{ json: { developer_chat_id: '8677383067', message } }];
